import { readFileSync } from "node:fs";
import path from "node:path";
import { parseSync } from "oxc-parser";
import type { Plugin, ResolvedConfig } from "vite";
import { createFilter } from "vite";
import {
  generateChannelsModule,
  generateHandlersMapModule,
} from "./plugin/codegen.js";
import {
  extractNonExportedHandlerNames,
  scanForHandlers,
  transform,
} from "./plugin/transform.js";
import type { ElectronActionsOptions } from "./types.js";

// ── Internal virtual module IDs ────────────────────────────────

// Generated by env:"main" — exports a map of { channel: handlerFn }
const HANDLERS_MAP_ID = "electron-actions:handlers-map";
const RESOLVED_HANDLERS_MAP_ID = "\0electron-actions-handlers-map";

// Generated by env:"preload" — exports a map of { fnName: channelString }
const CHANNELS_ID = "electron-actions:channels";
const RESOLVED_CHANNELS_ID = "\0electron-actions-channels";

// electron-actions:non-exported-actions: is only used internally by the main
// plugin to re-export non-exported "use node" functions from a source file so
// that ipcMain.handle() can reference them. The main plugin has no transform
// hook so no bypass guard is needed.
const RE_EXPORT_PREFIX = "electron-actions:non-exported-actions:";
const RESOLVED_RE_EXPORT_PREFIX = "\0electron-actions:non-exported-actions:";

// ── Plugin ─────────────────────────────────────────────────────

export function electronActions(options: ElectronActionsOptions): Plugin {
  // The optional chaining ("options?.env") is to help display a more specific
  // error message if the user forgets to pass an options object
  const env = options?.env;

  if (env === "renderer") {
    const includePattern = options.include ?? /\.[jt]sx?$/;
    const filter = createFilter(includePattern, options.exclude);

    return {
      name: "electron-actions:renderer",

      transform: {
        filter: { id: includePattern },
        handler(code, id) {
          // Guard for Vite < 6.3 where hook filters are not supported.
          if (!filter(id)) return null;

          const result = transform(code, id);
          if (!result) return null;

          return { code: result, map: null };
        },
      },
    };
  }

  if (env === "main") {
    const scanDirs = options.scanDirs ?? ["src"];
    const channelPrefix = options.channelPrefix ?? "";
    let root = process.cwd();

    return {
      name: "electron-actions:main",

      configResolved(config: ResolvedConfig) {
        root = config.root;
      },

      resolveId(id, importer) {
        if (id === HANDLERS_MAP_ID) return RESOLVED_HANDLERS_MAP_ID;

        if (id.startsWith(RE_EXPORT_PREFIX)) {
          return RESOLVED_RE_EXPORT_PREFIX + id.slice(RE_EXPORT_PREFIX.length);
        }

        // Resolve relative imports originating from a re-export file so that
        // transitive imports within re-exported files stay in the re-export graph.
        if (
          importer?.startsWith(RESOLVED_RE_EXPORT_PREFIX) &&
          id.startsWith(".")
        ) {
          const importerPath = importer.slice(RESOLVED_RE_EXPORT_PREFIX.length);
          const resolved = path.resolve(path.dirname(importerPath), id);
          for (const ext of [".ts", ".tsx", ".js", ".jsx", ""]) {
            try {
              readFileSync(resolved + ext);
              return RESOLVED_RE_EXPORT_PREFIX + resolved + ext;
            } catch {
              // try next extension
            }
          }
          return RESOLVED_RE_EXPORT_PREFIX + resolved;
        }

        return null;
      },

      load(id) {
        if (id === RESOLVED_HANDLERS_MAP_ID) {
          const registry = scanForHandlers(scanDirs, root, channelPrefix);

          return generateHandlersMapModule(registry, (fileId) => {
            const code = readFileSync(fileId, "utf-8");
            const { program } = parseSync(fileId, code);
            const nonExported = extractNonExportedHandlerNames(program);

            // Only use a re-export wrapper for files that have non-exported
            // "use node" functions that need re-exporting. All other files are
            // imported directly.
            return nonExported.length > 0
              ? `${RE_EXPORT_PREFIX}${fileId}`
              : fileId;
          });
        }

        if (id.startsWith(RESOLVED_RE_EXPORT_PREFIX)) {
          const filePath = id.slice(RESOLVED_RE_EXPORT_PREFIX.length);
          const code = readFileSync(filePath, "utf-8");
          const { program } = parseSync(filePath, code);
          const nonExported = extractNonExportedHandlerNames(program);

          if (nonExported.length === 0) return code;

          const reExports = nonExported
            .map((name) => `export { ${name} }`)
            .join("\n");
          return `${code}\n${reExports}\n`;
        }

        return null;
      },
    };
  }

  if (env === "preload") {
    const scanDirs = options.scanDirs ?? ["src"];
    const channelPrefix = options.channelPrefix ?? "";
    let root = process.cwd();

    return {
      name: "electron-actions:preload",

      configResolved(config: ResolvedConfig) {
        root = config.root;
      },

      resolveId(id) {
        if (id === CHANNELS_ID) return RESOLVED_CHANNELS_ID;
        return null;
      },

      load(id) {
        if (id === RESOLVED_CHANNELS_ID) {
          const registry = scanForHandlers(scanDirs, root, channelPrefix);
          return generateChannelsModule(registry, channelPrefix);
        }

        return null;
      },
    };
  }

  throw new Error(
    `[electron-actions] Unknown env: "${env}". Must be "renderer", "main", or "preload".`,
  );
}

export type { ElectronActionsOptions } from "./types.js";
